using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools ---
var tools = new ResearchTools();

var searchTool = AIFunctionFactory.Create(
    tools.SearchWebAsync,
    new AIFunctionFactoryOptions
    {
        Name = "search_web",
        Description = "Search the web for information on a query. Returns a list of result snippets.",
    });

var saveNoteTool = AIFunctionFactory.Create(
    tools.SaveNote,
    new AIFunctionFactoryOptions
    {
        Name = "save_note",
        Description = "Save a research note with a title and body. Use this to record key findings.",
    });

var readNotesTool = AIFunctionFactory.Create(
    tools.ReadNotes,
    new AIFunctionFactoryOptions
    {
        Name = "read_notes",
        Description = "Read all saved research notes so far.",
    });

// --- Agent setup ---
IChatClient chatClient = new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient();

var agentOptions = new ChatClientAgentOptions
{
    Id = "research-agent",
    Name = "Research Agent",
    Instructions = """
        You are a research agent. Your job is to research a topic thoroughly by
        searching the web, taking notes on key findings, and then producing a
        final summary.

        Workflow:
        1. Break the user's topic into 2-3 specific search queries.
        2. For each query, call search_web to find information.
        3. After each search, call save_note to record the most important findings.
        4. After all searches are complete, call read_notes to review everything.
        5. Produce a final, well-structured summary with sections and bullet points.

        Always cite the source URLs in your notes and final summary.
        """,
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        ToolMode = ChatToolMode.Auto,
        Tools = [searchTool, saveNoteTool, readNotesTool],
    },
};

var agent = new ChatClientAgent(chatClient, agentOptions);

// --- Run ---
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    topic, session, cancellationToken: CancellationToken.None))
{
    if (update.Text is { Length: > 0 } text)
        Console.Write(text);
}

Console.WriteLine("\n");

// Print collected notes
var notes = tools.ReadNotes();
if (notes.Count > 0)
{
    Console.WriteLine("═══════════════════════════════════════");
    Console.WriteLine("📝 Research Notes Collected");
    Console.WriteLine("═══════════════════════════════════════");
    foreach (var note in notes)
        Console.WriteLine($"\n### {note.Title}\n{note.Body}\n");
}

return;

// --- Helpers ---
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? throw new InvalidOperationException("No topic provided.")
        : input;
}

// --- Tool implementations ---

/// <summary>Tools available to the research agent.</summary>
sealed class ResearchTools
{
    private readonly List<Note> _notes = [];
    private readonly HttpClient _http = new() { Timeout = TimeSpan.FromSeconds(15) };

    /// <summary>Searches the web using DuckDuckGo Lite (no API key needed).</summary>
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("User-Agent", "ResearchAgent/1.0");

            using var response = await _http.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync(cancellationToken);

            return ParseDuckDuckGoResults(html, query);
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ⚠️  Search failed: {ex.Message}");
            return [new SearchResult($"Search for '{query}' failed: {ex.Message}", "", query)];
        }
    }

    /// <summary>Saves a research note.</summary>
    public string SaveNote(
        [Description("A short title for this note")] string title,
        [Description("The body content of the note with key findings")] string body)
    {
        _notes.Add(new Note(title, body));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully. Total notes: {_notes.Count}";
    }

    /// <summary>Returns all saved notes.</summary>
    public IReadOnlyList<Note> ReadNotes() => _notes.AsReadOnly();

    private static List<SearchResult> ParseDuckDuckGoResults(string html, string query)
    {
        var results = new List<SearchResult>();

        // DuckDuckGo Lite returns a simple HTML page with result snippets in
        // table rows. We extract text between <td> tags that contain snippets.
        var snippetMarker = "class=\"result-snippet\"";
        var linkMarker = "class=\"result-link\"";
        var idx = 0;

        while (results.Count < 5)
        {
            var linkIdx = html.IndexOf(linkMarker, idx, StringComparison.Ordinal);
            if (linkIdx < 0) break;

            var hrefStart = html.LastIndexOf("href=\"", linkIdx, StringComparison.Ordinal);
            var url = "";
            if (hrefStart >= 0)
            {
                hrefStart += 6;
                var hrefEnd = html.IndexOf('"', hrefStart);
                if (hrefEnd > hrefStart)
                    url = html[hrefStart..hrefEnd];
            }

            // Get link text
            var tagEnd = html.IndexOf('>', linkIdx);
            var closingTag = html.IndexOf("</a>", tagEnd, StringComparison.Ordinal);
            var linkText = tagEnd >= 0 && closingTag > tagEnd
                ? StripHtml(html[(tagEnd + 1)..closingTag]).Trim()
                : "";

            idx = closingTag > 0 ? closingTag : linkIdx + linkMarker.Length;

            var snippetIdx = html.IndexOf(snippetMarker, idx, StringComparison.Ordinal);
            var snippet = "";
            if (snippetIdx >= 0)
            {
                var sTagEnd = html.IndexOf('>', snippetIdx);
                var sCloseTag = html.IndexOf("</td>", sTagEnd, StringComparison.Ordinal);
                if (sTagEnd >= 0 && sCloseTag > sTagEnd)
                {
                    snippet = StripHtml(html[(sTagEnd + 1)..sCloseTag]).Trim();
                    idx = sCloseTag;
                }
            }

            if (!string.IsNullOrWhiteSpace(linkText))
                results.Add(new SearchResult(snippet, url, linkText));
        }

        return results.Count > 0
            ? results
            : [new SearchResult($"No detailed results found. Try a different query for: {query}", "", query)];
    }

    private static string StripHtml(string html)
    {
        var result = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
        result = WebUtility.HtmlDecode(result);
        return System.Text.RegularExpressions.Regex.Replace(result, @"\s+", " ").Trim();
    }
}

record SearchResult(
    [property: Description("A snippet or summary from the search result")] string Snippet,
    [property: Description("The URL of the search result")] string Url,
    [property: Description("The title of the search result")] string Title);

